export const meta = {
  name: 'audit-project-dual-review-public-demo',
  description: '脱敏示例：分区并行审 → 每条发现对抗验证 → 汇总待拍板',
  phases: [{ title: 'Find' }, { title: 'Verify' }, { title: 'Synthesize' }],
}

const ROOT = '/workspace/sample-agent-app'

const ZONES = [
  {
    key: 'eval-runner',
    label: '评估编排核心',
    files: ["src/core/eval-runner.ts"],
    focus: '步骤树、事件映射、超时兜底、并发状态机一致性',
  },
  {
    key: 'http-routes',
    label: 'HTTP 入口与路由',
    files: ["src/server.ts", "src/routes/approvals.ts", "src/routes/release.ts", "src/ui/html.ts"],
    focus: '路由鉴权挂载顺序、输入校验、路径穿越、未捕获异常、Host header 语义',
  },
  {
    key: 'auth-gate',
    label: '鉴权与门禁（安全关键）',
    files: ["src/auth/session.ts", "src/auth/group-gate.ts", "src/auth/search-gate.ts", "src/audit/audit-log.ts"],
    focus: 'token 校验时序安全、fail-open vs fail-close、CSRF、身份伪造、审计脱敏',
  },
  {
    key: 'state-config',
    label: '持久化/状态/配置',
    files: ["src/state/task-store.ts", "src/config.ts", "src/util.ts"],
    focus: '并发写文件竞态、JSON 损坏恢复、配置解析回退、原子写、锁',
  },
  {
    key: 'external-io',
    label: '外部 IO（消息/文档/播报）',
    files: ["src/integrations/chat.ts", "src/integrations/docs.ts", "src/notify/release-announce.ts"],
    focus: 'await 缺失导致推送丢失、重试/幂等、token 过期处理、网络错误吞没',
  },
  {
    key: 'pipeline-batch',
    label: '抓取批处理与资源管理',
    files: ["pipeline/run-batch.ts", "pipeline/run-one.ts", "pipeline/collect/collect-one.ts", "shared/proc.ts"],
    focus: '浏览器进程/上下文泄漏、fetch 无超时挂起、孤儿进程、并发名额争抢',
  },
  {
    key: 'pipeline-eval',
    label: '终判/规则/LLM 评估',
    files: ["pipeline/evaluate/final-judge.ts", "pipeline/evaluate/rules.ts", "pipeline/evaluate/landing-probe.ts"],
    focus: '子进程超时与进程树杀、规则判定口径、结果解析健壮性、统计漏算',
  },
  {
    key: 'pipeline-write',
    label: '写表与共享工具',
    files: ["pipeline/write/write-sheet.ts", "pipeline/write/render-report.ts", "shared/io.ts"],
    focus: '写表行定位错位、并发 addSheet 竞态、部分失败处理、目标行计算',
  },
  {
    key: 'promote',
    label: '发布晋级与重启',
    files: ["scripts/promote.ts", "scripts/safe-restart.ts"],
    focus: '受保护分支直推、预演合并测试还原、并发锁、重启前任务检查、事务幂等',
  },
  {
    key: 'scripts-fetch',
    label: '抓取数据脚本',
    files: ["scripts/create-fetch-task.ts", "scripts/chunked-resume.ts", "scripts/fetch-review-top3.ts"],
    focus: 'fetch 无超时、查询拼接注入、cookie 过期、并发浏览器堆积、错误吞没',
  },
  {
    key: 'frontend',
    label: '前端逻辑',
    files: ["public/app.ts", "public/dashboard.ts", "public/board-schema.ts"],
    focus: 'XSS、轮询泄漏、状态不一致、错误未处理的 fetch、内存泄漏',
  },
]

const FINDINGS_SCHEMA = {
  type: 'object',
  properties: { findings: { type: 'array', items: { type: 'object' } } },
  required: ['findings'],
}

const VERDICT_SCHEMA = {
  type: 'object',
  properties: { isReal: { type: 'boolean' }, confidence: { type: 'string' }, reasoning: { type: 'string' } },
  required: ['isReal', 'confidence', 'reasoning'],
}

function findPrompt(zone) {
  return `你是资深代码审查者，正在审计「示例评估看板项目」（公开脱敏示例）。
主链路：读取任务 → 抓取页面/接口结果 → 规则+LLM 终判 → 写回报告。
项目根目录：${ROOT}

【你负责的审查分区：${zone.label}】
请用 Read 工具完整读取以下文件（必要时 Grep 它们调用/被调用的上下文，但审查范围聚焦这些文件）：
${zone.files.map(f => `  - ${ROOT}/${f}`).join('\n')}

【重点关注】${zone.focus}

【要求】
- 找真实的漏洞、缺陷、需重构处。优先正确性 bug、安全漏洞、资源泄漏、并发竞态、错误处理缺口。
- 每条发现必须引用具体代码作为 evidence（行号 + 关键片段），不能泛泛而谈、不能臆测。
- 宁缺毋滥：没把握成立的不要报。

返回结构化 findings 数组。`
}

function verifyPrompt(f) {
  return `你是严格的代码审查验证者，任务是【对抗性地验证】下面这条审查发现是否真实成立。默认怀疑它是误报，除非代码证据确凿。
项目根目录：${ROOT}

【待验证的发现】
标题：${f.title}
文件：${f.file}
行号：${f.line}
严重度：${f.severity}（${f.category}）
描述：${f.description}
建议：${f.suggestion}

【你必须做的】
1. 用 Read 工具打开 ${ROOT}/${f.file}，定位到 ${f.line} 附近的示例代码。
2. 核对上下文是否支持这个判断。
3. 给出裁决：isReal=true 仅当证据确凿。`
}

const zoneResults = await pipeline(
  ZONES,
  (zone) => agent(findPrompt(zone), {
    label: `审:${zone.key}`,
    phase: 'Find',
    schema: FINDINGS_SCHEMA,
    agentType: 'Explore',
  }).then(r => ({ zone, findings: (r && r.findings) || [] })),
  (res) => parallel(res.findings.map(f => () =>
    agent(verifyPrompt(f), {
      label: `验:${f.file.split('/').pop()}:${f.line}`,
      phase: 'Verify',
      schema: VERDICT_SCHEMA,
      agentType: 'Explore',
    }).then(v => ({ ...f, verdict: v }))
  ))
)

